import{_ as r,o as a,c as i,ag as t}from"./chunks/framework.CAXxHpAX.js";const f=JSON.parse('{"title":"Fase 3: Storage-tiering, replikering & backup","description":"","frontmatter":{"title":"Fase 3: Storage-tiering, replikering & backup","phase":3,"topic":"infrastruktur","personas":["arkitekt","driftsleder"],"tags":["storage","tiering","replikering","backup","RPO","deduplikering","immutable"],"priority":"kritisk-sti","dependencies":[2]},"headers":[],"relativePath":"faser/03-storage.md","filePath":"faser/03-storage.md"}'),s={name:"faser/03-storage.md"};function n(o,e,p,l,g,k){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="fase-3-storage-tiering-replikering-backup" tabindex="-1">Fase 3: Storage-tiering, replikering &amp; backup <a class="header-anchor" href="#fase-3-storage-tiering-replikering-backup" aria-label="Permalink to &quot;Fase 3: Storage-tiering, replikering &amp; backup&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="critical-path-badge">Kritisk sti</span></span><span><strong>Afhænger af:</strong> Fase 2 (HCI-platform)</span><span><strong>Blokerer:</strong> Fase 9</span></div><div class="persona-badges"><span class="persona-badge arkitekt">🏗️ Arkitekt</span><span class="persona-badge driftsleder">⚙️ Driftsleder</span></div><p>Det vurderes, at en differentieret storage-strategi er afgørende for at balancere performance, resiliency og omkostningseffektivitet på tværs af kommunernes vidt forskellige workload-profiler.</p><ul><li><p>En tiering-model med mindst to niveauer (høj-performance og kapacitet) defineres, og placering sker automatisk baseret på workloadens kritikalitetsklasse.</p></li><li><p>Synkron replikering konfigureres for Tier 1-data (RPO = 0) mellem de to primære sites; asynkron replikering for Tier 2-3 data med differentierede RPO&#39;er.</p></li><li><p>Deduplikering og komprimering aktiveres som standard på alle storage-lag for at maksimere kapacitetsudnyttelsen.</p></li><li><p>Backup-strategi implementeres med differentierede politikker pr. kritikalitetsklasse, immutable kopier og opbevaring på mindst to geografisk adskilte lokationer.</p></li><li><p>Automatiseret gendannelsesverifikation konfigureres, så backup-integriteten valideres løbende uden manuel intervention.</p></li></ul>',5)])])}const m=r(s,[["render",n]]);export{f as __pageData,m as default};
